'use client'

import { useState, useEffect } from 'react' // Added useEffect
import { supabase } from '@/lib/supabase' // Import your client
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table'
import { Input } from '@/components/ui/input'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Search } from 'lucide-react'

interface Registration {
  id: string
  studentName: string
  email: string
  eventName: string
  registrationDate: string
  status: 'Confirmed' | 'Pending' | 'Cancelled'
}

const statusColors: Record<string, string> = {
  Confirmed: 'bg-green-100 text-green-800',
  Pending: 'bg-yellow-100 text-yellow-800',
  Cancelled: 'bg-red-100 text-red-800'
}

export default function RegistrationsTab() {
  const [searchTerm, setSearchTerm] = useState('')
  const [filterStatus, setFilterStatus] = useState<'All' | 'Confirmed' | 'Pending' | 'Cancelled'>('All')
  
  // 1. Add state for real data and loading status
  const [registrations, setRegistrations] = useState<Registration[]>([])
  const [isLoading, setIsLoading] = useState(true)

  // 2. Fetch data when the component loads
  useEffect(() => {
    async function fetchRegistrations() {
      const { data, error } = await supabase
        .from('registrations')
        .select('*')
        .order('created_at', { ascending: false })

      if (error) {
        console.error('Error fetching registrations:', error)
      } else {
        // Map snake_case from DB to camelCase for your UI
        const formattedData = data.map(row => ({
          id: row.id,
          studentName: row.student_name,
          email: row.email,
          eventName: row.event_name,
          registrationDate: row.registration_date,
          status: row.status as any
        }))
        setRegistrations(formattedData)
      }
      setIsLoading(false)
    }

    fetchRegistrations()
  }, [])

  // 3. Update the filter logic to use the real state
  const filteredRegistrations = registrations.filter((reg) => {
    const matchesSearch =
      reg.studentName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      reg.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      reg.eventName.toLowerCase().includes(searchTerm.toLowerCase())
    const matchesStatus = filterStatus === 'All' || reg.status === filterStatus
    return matchesSearch && matchesStatus
  })

  return (
    <Card>
      <CardHeader>
        <CardTitle>Event Registrations</CardTitle>
        <CardDescription>Manage and view all event registrations</CardDescription>
      </CardHeader>
      <CardContent>
        <div className="mb-4 flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-2 top-2.5 h-4 w-4 text-gray-400" />
            <Input
              placeholder="Search by name, email, or event..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-8"
            />
          </div>
        </div>
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Student Name</TableHead>
              <TableHead>Email</TableHead>
              <TableHead>Event</TableHead>
              <TableHead>Registration Date</TableHead>
              <TableHead>Status</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {isLoading ? (
              <TableRow>
                <TableCell colSpan={5} className="text-center">Loading...</TableCell>
              </TableRow>
            ) : filteredRegistrations.length > 0 ? (
              filteredRegistrations.map((reg) => (
                <TableRow key={reg.id}>
                  <TableCell>{reg.studentName}</TableCell>
                  <TableCell>{reg.email}</TableCell>
                  <TableCell>{reg.eventName}</TableCell>
                  <TableCell>{new Date(reg.registrationDate).toLocaleDateString()}</TableCell>
                  <TableCell>
                    <Badge className={statusColors[reg.status]}>
                      {reg.status}
                    </Badge>
                  </TableCell>
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={5} className="text-center">No registrations found</TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  )
}